 "summary": "Retrieve a single attachment for a received email",
 "parameters": [
 {
 "name": "email_id",
 "in": "path",
 "required": true,
 "schema": {
 "type": "string",
 "format": "uuid"
 },
 "description": "The ID of the received email."
 },
 {
 "name": "attachment_id",
 "in": "path",
 "required": true,
 "schema": {
 "type": "string",
 "format": "uuid"
 },
 "description": "The ID of the attachment."
 }
 ],
 "responses": {
 "200": {
 "description": "OK",
 "content": {
 "application/json": {
 "schema": {
 "$ref": "#/components/schemas/RetrievedAttachment"
 }
 }
 }
 }
 }
 }
 },
 "/domains": {
 "post": {
 "tags": [
 "Domains"
 ],
 "summary": "Create a new domain",
 "requestBody": {
 "content": {
 "application/json": {
 "schema": {
 "$ref": "#/components/schemas/CreateDomainRequest"
 }
 }
 }
 },
 "responses": {
 "201": {
 "description": "OK",
 "content": {
 "application/json": {
 "schema": {
 "$ref": "#/components/schemas/CreateDomainResponse"
 }
 }
 }
 }
 }
 },
 "get": {
 "tags": [
 "Domains"
 ],
 "summary": "Retrieve a list of domains",
